c
chunk_start = (const char*)chunk->memory;
chunk_end = chunk_start +
(chunk->num_blocks * pool->block_size);
if (target >= chunk_start && target < chunk_end)
→ FOUND! Proceed to STEP 4
else
→ Update blocks_before += chunk->num_blocks
→ Advance: chunk = chunk->next
→ Loop to STEP 2

c
// Within found chunk:
offset = target - chunk_start;
// Alignment check
if (offset % pool->block_size != 0)
return -1;  // Misaligned pointer!
// Local index within this chunk
local_index = offset / pool->block_size;

c
// Global index = blocks from previous chunks
//              + local index within current chunk
return blocks_before + local_index;
